stages.example:
- stage: extract
  args:
    - { selector: "h1", method: "text", as: "title" }
    - { selector: "span.price", method: "price", as: "price_numeric" }

- stage: load_csv
  args:
    - { path: "s3a://bucket/input.csv", header: "true", inferSchema: "true" }

- stage: load_union
  args:
    - { format: "csv", path: "s3a://bucket/a.csv", options: { header: "true" } }
    - { format: "csv", path: "s3a://bucket/b.csv", options: { header: "true" } }

- stage: load_mongodb
  args:
    - { uri: "mongodb://host:27017", database: "mydb", collection: "products" }

- stage: oecdAPI
  args:
    - { dataset: "MEI_FIN", filter: "IRSTCI.ITA.M", as: "oecd_short_rates" }

- stage: worldBankAPI
  args:
    - { country: "all", indicator: "NY.GDP.MKTP.CD", per_page: 1000, numPartitions: 16, params: { date: "1960:2024" }, as: "wb_gdp" }

- stage: fredAPI
  args:
    - { series: "GDPC1", params: { observation_start: "2018-01-01" }, as: "fred_gdp" }

- stage: bancaItaliaAPI
  args:
    - { flow: "BIP_PUB__BPM6", key: "M.IT....", as: "bdi_bpm6" }

- stage: overpassAPI
  args:
    - { query: "[out:json]; area['ISO3166-1'='IT'][admin_level=2]->.it; node['amenity'='hospital'](area.it); out tags;", as: "osm_hospitals" }

- stage: enrichMatchingScore
  args:
    - { ean_field: "EAN number", extracted_prefix: "prod_", output_field: "matching_score" }

- stage: propertyCluster
  args:
    - { algorithm: "kmeans", k: 5, features: ["latitude", "longitude", "price_per_sqm"] }

- stage: propertyClusterML
  args:
    - { algorithm: "gmm", k: 4, features: ["price_per_sqm", "area_sqm"] }
